mapper.select:
SELECT COALESCE( ( SELECT dv.time FROM ${datatablename} dv WHERE time > ( SELECT dv.time FROM ${datatablename} dv WHERE dv.time <= ( SELECT dv.time FROM ${datatablename} dv LEFT JOIN device d ON d.id = dv.id_device LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone WHERE dv.error = 0 ORDER BY dv.time DESC LIMIT 1 ) AND dv.error <> 0 ORDER BY time DESC LIMIT 1 ) ORDER BY time ASC LIMIT 1
), (
SELECT dv.time FROM ${datatablename} dv WHERE time > ( SELECT time FROM ${datatablename} WHERE error = 139 ORDER BY time DESC LIMIT 1 )
ORDER BY dv.time ASC LIMIT 1
),
( SELECT time FROM ${datatablename} WHERE time > ( SELECT time FROM ${datatablename} WHERE time < ( SELECT time FROM ${datatablename} WHERE error != 139 ORDER BY time DESC LIMIT 1 ) AND error = 139 ORDER BY time DESC LIMIT 1 ) AND error != 139 LIMIT 1 ),
( SELECT time FROM ${datatablename} WHERE error != 139 ORDER BY time DESC LIMIT 1 ) ) AS end_date;

SELECT CASE WHEN data_send_time = 1 AND total_no_comm >= 23 THEN 1 WHEN data_send_time = 2 AND total_no_comm >= 8 THEN 1 WHEN data_send_time = 3 AND total_no_comm >= 120 THEN 1 ELSE 0 END AS is_no_comm,
data_send_time, total_no_comm
FROM ( SELECT s.data_send_time, COUNT(*) AS total_no_comm FROM ${datatablename} u LEFT JOIN device d ON d.id = u.id_device LEFT JOIN site s ON s.id = d.id_site WHERE u.error = 0 AND u.time >= #{end_date}
GROUP BY s.data_send_time ) t;

SELECT s.id, s.`name`, s.id_time_zone, t.`value` AS time_zone_value, s.start_date_time, s.end_date_time, s.cf_start_time, s.cf_end_time, s.ac_capacity, s.dc_capacity FROM site s INNER JOIN time_zone t ON t.id = s.id_time_zone WHERE s.`status` = 1 AND s.`is_delete` = 0 AND s.cf_start_time IS NOT NULL AND s.cf_end_time IS NOT NULL AND ( (s.cf_start_time < s.cf_end_time AND HOUR(CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', t.`value`)) >= s.cf_start_time + 2 AND HOUR(CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', t.`value`)) <= s.cf_end_time - 2) OR (s.cf_start_time > s.cf_end_time AND ( HOUR(CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', t.`value`)) >= s.cf_start_time + 2 OR HOUR(CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', t.`value`)) <= s.cf_end_time - 2 )) ) AND s.run_on_server IN
#{item}
GROUP BY s.id
